-- Adds GUDID enrichment to catalog_reference_items: source/udi/market columns
-- and image_search_url for every row. Reseeds 548 rows: 536 curated India items
-- (price-banded, 6 categories) plus 12 sample GUDID entries pulled from the
-- AccessGUDID FDA dump (no price; identified by UDI).
--
-- Re-runnable: TRUNCATE + INSERT, so the migration can run on a fresh DB or
-- re-apply after a catalogue refresh and stay consistent.

ALTER TABLE public.catalog_reference_items
  ADD COLUMN IF NOT EXISTS source           text NOT NULL DEFAULT 'curated',
  ADD COLUMN IF NOT EXISTS udi              text,
  ADD COLUMN IF NOT EXISTS market           text NOT NULL DEFAULT 'India',
  ADD COLUMN IF NOT EXISTS image_search_url text;

CREATE UNIQUE INDEX IF NOT EXISTS catalog_ref_udi_unique
  ON public.catalog_reference_items (udi)
  WHERE udi IS NOT NULL;

CREATE INDEX IF NOT EXISTS catalog_ref_source_idx
  ON public.catalog_reference_items (source);

TRUNCATE public.catalog_reference_items;

INSERT INTO public.catalog_reference_items
  (id, source, udi, item_name, brand, model, category, sub_category, type,
   key_specifications, price_inr_low, price_inr_high, market, image_search_url, notes)
